import java.util.Arrays;

public class Solution {
    public static long solve(long[] nums) {
        int n = nums.length;
        long[] sortedNums = Arrays.copyOf(nums, n);
        Arrays.sort(sortedNums);
        if (Arrays.equals(nums, sortedNums)) {
            return 0;
        }

        long maxK = (1L << 60) - 1; // Start with all bits set
        boolean hasMismatch = false;
        for (int i = 0; i < n; i++) {
            if (nums[i] != sortedNums[i]) {
                maxK &= (nums[i] & sortedNums[i]);
                hasMismatch = true;
            }
        }

        if (!hasMismatch) {
            return 0;
        }

        // Check if maxK is valid
        boolean valid = true;
        for (int i = 0; i < n; i++) {
            if (nums[i] != sortedNums[i]) {
                if ((nums[i] & maxK) != maxK || (sortedNums[i] & maxK) != maxK) {
                    valid = false;
                    break;
                }
            }
        }

        if (valid) {
            return maxK;
        }

        // Find the largest k <= maxK that is valid
        long k = maxK;
        for (int b = 60; b >= 0; b--) {
            long mask = 1L << b;
            if ((k & mask) == 0) {
                continue;
            }
            long newK = k & ~mask;
            valid = true;
            for (int i = 0; i < n; i++) {
                if (nums[i] != sortedNums[i]) {
                    if ((nums[i] & newK) != newK || (sortedNums[i] & newK) != newK) {
                        valid = false;
                        break;
                    }
                }
            }
            if (valid) {
                k = newK;
            }
        }

        return k;
    }
}
